package mailer

import (
	"strings"
	"testing"
)

func TestSanitizeHeader(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{"clean value", "user@example.com", "user@example.com"},
		{"strips CR", "user@example.com\rBcc: evil@evil.com", "user@example.comBcc: evil@evil.com"},
		{"strips LF", "user@example.com\nBcc: evil@evil.com", "user@example.comBcc: evil@evil.com"},
		{"strips CRLF", "user@example.com\r\nBcc: evil@evil.com", "user@example.comBcc: evil@evil.com"},
		{"multiple injections", "a\r\nb\r\nc", "abc"},
		{"empty string", "", ""},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := sanitizeHeader(tt.input)
			if got != tt.want {
				t.Errorf("sanitizeHeader(%q) = %q, want %q", tt.input, got, tt.want)
			}
		})
	}
}

func TestBuildMessage(t *testing.T) {
	msg := buildMessage("user@example.com", "Test Subject", "<p>Hello</p>")

	checks := []struct {
		desc string
		want string
	}{
		{"From header", "From: " + defaultFrom},
		{"To header", "To: user@example.com"},
		{"Subject header", "Subject: Test Subject"},
		{"MIME-Version header", "MIME-Version: 1.0"},
		{"Content-Type header", "Content-Type: text/html; charset=utf-8"},
		{"HTML body", "<p>Hello</p>"},
	}

	for _, c := range checks {
		t.Run(c.desc, func(t *testing.T) {
			if !strings.Contains(msg, c.want) {
				t.Errorf("message missing %q\ngot:\n%s", c.want, msg)
			}
		})
	}
}

func TestBuildMessage_headersSeparatedFromBody(t *testing.T) {
	msg := buildMessage("to@example.com", "Subj", "<b>body</b>")
	// RFC 2822: headers and body separated by blank line (CRLF CRLF)
	if !strings.Contains(msg, "\r\n\r\n") {
		t.Error("message missing blank line between headers and body")
	}
	parts := strings.SplitN(msg, "\r\n\r\n", 2)
	if len(parts) != 2 {
		t.Fatal("could not split headers from body")
	}
	if !strings.Contains(parts[1], "<b>body</b>") {
		t.Errorf("body not after blank line, got: %q", parts[1])
	}
}

