package consumer

import (
	"encoding/json"
	"errors"
	"testing"

	"notification-service/internal/handlers"
)

func captureMailSender(calls *[]mailCall) handlers.MailSender {
	return func(to, subject, html string) error {
		*calls = append(*calls, mailCall{to: to, subject: subject, html: html})
		return nil
	}
}

type mailCall struct {
	to, subject, html string
}

func TestDispatch_passwordReset(t *testing.T) {
	payload := handlers.PasswordResetPayload{
		To:      "user@example.com",
		Subject: "Reset your password",
		Data: struct {
			ResetURL  string `json:"reset_url"`
			ExpiresIn string `json:"expires_in"`
		}{
			ResetURL:  "https://example.com/reset",
			ExpiresIn: "15 minutes",
		},
	}
	rawPayload, _ := json.Marshal(payload)

	msg := emailMessage{
		EventType: "email.password_reset",
		Payload:   json.RawMessage(rawPayload),
	}

	var calls []mailCall
	mailSender = captureMailSender(&calls)
	t.Cleanup(func() { mailSender = nil })

	if err := dispatch(msg); err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if len(calls) != 1 {
		t.Fatalf("expected 1 send call, got %d", len(calls))
	}
	if calls[0].to != payload.To {
		t.Errorf("To = %q, want %q", calls[0].to, payload.To)
	}
}

func TestDispatch_emailVerification(t *testing.T) {
	payload := handlers.EmailVerificationPayload{
		To:      "newuser@example.com",
		Subject: "Verify your email",
		Data: struct {
			VerifyURL string `json:"verify_url"`
			ExpiresIn string `json:"expires_in"`
		}{
			VerifyURL: "https://example.com/verify",
			ExpiresIn: "24 hours",
		},
	}
	rawPayload, _ := json.Marshal(payload)

	msg := emailMessage{
		EventType: "email.verification",
		Payload:   json.RawMessage(rawPayload),
	}

	var calls []mailCall
	mailSender = captureMailSender(&calls)
	t.Cleanup(func() { mailSender = nil })

	if err := dispatch(msg); err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if len(calls) != 1 {
		t.Fatalf("expected 1 send call, got %d", len(calls))
	}
	if calls[0].to != payload.To {
		t.Errorf("To = %q, want %q", calls[0].to, payload.To)
	}
}

func TestDispatch_unknownEventType_returnsNil(t *testing.T) {
	msg := emailMessage{
		EventType: "email.unknown_future_type",
		Payload:   json.RawMessage(`{}`),
	}

	var calls []mailCall
	mailSender = captureMailSender(&calls)
	t.Cleanup(func() { mailSender = nil })

	if err := dispatch(msg); err != nil {
		t.Errorf("expected nil for unknown event type, got %v", err)
	}
	if len(calls) != 0 {
		t.Errorf("expected no send calls for unknown event type, got %d", len(calls))
	}
}

func TestDispatch_malformedPayload_returnsError(t *testing.T) {
	msg := emailMessage{
		EventType: "email.password_reset",
		Payload:   json.RawMessage(`not valid json`),
	}

	mailSender = func(_, _, _ string) error { return nil }
	t.Cleanup(func() { mailSender = nil })

	if err := dispatch(msg); err == nil {
		t.Error("expected error for malformed payload, got nil")
	}
}

func TestDispatch_senderError_propagates(t *testing.T) {
	payload := handlers.PasswordResetPayload{
		To:      "user@example.com",
		Subject: "Reset",
	}
	rawPayload, _ := json.Marshal(payload)

	msg := emailMessage{
		EventType: "email.password_reset",
		Payload:   json.RawMessage(rawPayload),
	}

	sendErr := errors.New("smtp down")
